import numpy as np

def _doc2ids(label_one_hot: bool, s2_label_dict: dict, data_list: dict, maxlen: int, s2_label: bool, char2idx: dict, ftype: int) -> dict:
    doc2ids = {}
    for f, seqs in data_list.items():
        if ftype in (1, 3):
            if f == 'label':
                indices = [int(s.strip()) for s in seqs]
                if label_one_hot:
                    max_idx = max(indices) if indices else 0
                    doc2ids[f] = np.eye(max_idx + 1)[indices]
                else:
                    doc2ids[f] = np.array(indices)
            else:
                converted = []
                for seq in seqs:
                    idx_list = [char2idx.get(c, 1) for c in seq]
                    idx_list = idx_list[:maxlen]
                    idx_list += [0] * (maxlen - len(idx_list))
                    converted.append(idx_list)
                doc2ids[f] = np.array(converted)
        elif ftype == 2:
            if f == 's2' and s2_label:
                converted = []
                for seq in seqs:
                    idx = s2_label_dict.get(seq.strip(), 1)
                    converted.append([idx] * maxlen)
                doc2ids[f] = np.array(converted)
            else:
                converted = []
                for seq in seqs:
                    idx_list = [char2idx.get(c, 1) for c in seq]
                    idx_list = idx_list[:maxlen]
                    idx_list += [0] * (maxlen - len(idx_list))
                    converted.append(idx_list)
                doc2ids[f] = np.array(converted)
    return doc2ids
