```python
import numpy as np

def meshgrid(xi, indexing, sparse, copy_):
    ndim = len(xi)
    s0 = (1,) * ndim
    output = [np.asarray(x).reshape(s0[:i] + (len(x),) + s0[i+1:]) for i, x in enumerate(xi)]
    shape = [len(x) for x in xi]

    if indexing == 'xy' and ndim > 1:
        shape[0], shape[1] = shape[1], shape[0]
        output[0] = output[0].reshape(shape)
        output[1] = output[1].reshape(shape)

    if sparse:
        return [np.copy(x) if copy_ else x for x in output]
    else:
        mult_fact = np.ones(shape)
        if copy_:
            return [x * mult_fact for x in output]
        else:
            return np.broadcast_arrays(*output)
