import numpy as np

def append(arr, values, axis):
    arr = np.asanyarray(arr)
    if axis is None:
        arr = arr.ravel()
        values = np.ravel(values)
        axis = arr.ndim - 1

    if arr.size > 0 or values.size > 0:
        return np.concatenate((arr, values), axis=axis)
    return arr
