import numpy as np

def keras_pad_seqs(sequences, maxlen, dtype, padding, truncating, value):
    num_samples = len(sequences) if hasattr(sequences, '__len__') else 0

    lengths = [len(seq) for seq in sequences]

    if maxlen is None:
        maxlen = max(lengths) if lengths else 0

    sample_shape = ()
    for seq in sequences:
        if len(seq) > 0:
            sample_shape = np.array(seq).shape[1:]
            break

    x = np.full((num_samples, maxlen) + sample_shape, value, dtype=dtype)

    for i, seq in enumerate(sequences):
        if len(seq) == 0:
            continue

        if truncating == 'pre':
            truncated = seq[-maxlen:]
        else:
            truncated = seq[:maxlen]

        if len(truncated) > 0:
            if padding == 'post':
                x[i, :len(truncated)] = truncated
            else:
                x[i, -len(truncated):] = truncated

    return x
