import numpy as np

def generate_eps_MV(cor, T, dt, sims, mu):
    N = int(T / dt)
    if not isinstance(cor, np.ndarray):
        cor = np.array(cor)
    if mu is None:
        mu = np.zeros(cor.shape[0])
    mu = np.asarray(mu)
    return np.tile(mu, (N, sims, 1))
