import math

def get_cm(i, cm_coef, alpha, cl_ext, cd_ext, alpha_low_deg, alpha_high_deg, cm0):
    cm_new = cm0
    if alpha[i] < alpha_low_deg or alpha[i] > alpha_high_deg:
        if -165 <= alpha[i] <= 165:
            if abs(alpha[i]) < 0.01:
                cm_new = cm0
            elif alpha[i] > 0:
                rad = math.radians(alpha[i])
                x = cm_coef * math.tan(rad - math.pi / 2) + 0.25
                cm_new = cm0 - x * (cl_ext[i] * math.cos(rad) + cd_ext[i] * math.sin(rad))
            else:
                rad = math.radians(alpha[i])
                x = cm_coef * math.tan(-rad - math.pi / 2) + 0.25
                cm_new = -(cm0 - x * (-cl_ext[i] * math.cos(-rad) + cd_ext[i] * math.sin(-rad)))
        else:
            cm_new = cm_lookup.get(alpha[i], cm0)
    return cm_new
