import numpy as np
from scipy import signal

def idxsOfRelativeExtrema(x, maxima, allowEq, axis):
    x = np.asarray(x)
    if x.size == 0:
        return np.array([])
    if x.size == 1:
        return np.array([0])

    pad = -np.inf if maxima else np.inf

    if maxima:
        comp = np.greater_equal if allowEq else np.greater
    else:
        comp = np.less_equal if allowEq else np.less

    if x.ndim == 1:
        x_padded = np.append(x, pad)
        idxs = signal.argrelextrema(x_padded, comp, order=1)[0]
        return idxs
    else:
        if axis == 0:
            x_padded = np.pad(x, ((0, 1), (0, 0)), constant_values=pad)
            idxs = signal.argrelextrema(x_padded, comp, axis=0, order=1)[0]
        else:
            x_padded = np.pad(x, ((0, 0), (0, 1)), constant_values=pad)
            idxs = signal.argrelextrema(x_padded, comp, axis=1, order=1)[0]
        return idxs
