import numpy as np

def sp1(data, maxvalue, issuccessful):
    if not isinstance(data, (list, tuple, np.ndarray)):
        return (np.nan, np.nan, np.nan)

    if issuccessful is not None:
        if not isinstance(issuccessful, (list, tuple, np.ndarray)):
            return (np.nan, np.nan, np.nan)
        if len(issuccessful) != len(data):
            return (np.nan, np.nan, np.nan)

    data_arr = np.asarray(data)
    valid_mask = ~np.isnan(data_arr)
    dat = data_arr[valid_mask]

    if len(dat) == 0:
        return (np.nan, np.nan, np.nan)

    N = len(dat)

    if issuccessful is not None:
        issuccessful_arr = np.asarray(issuccessful)
        issuccessful_filtered = issuccessful_arr[valid_mask]
        succ_mask = np.asarray(issuccessful_filtered, dtype=bool)
        dat = dat[succ_mask]
    else:
        dat = dat[dat < maxvalue]

    count = len(dat)
    if count == 0:
        return (np.inf, 0.0, 0)

    succ_ratio = count / N
    mean_val = np.mean(dat) / succ_ratio
    return (mean_val, succ_ratio, count)
```

```python
import numpy as np

def sp(data, maxvalue, issuccessful, allowinf):
    # 1. Input Validation
    try:
        data = list(data)
    except TypeError:
        return (np.nan, np.nan, np.nan)

    # 2. Successful Condition Check
    if issuccessful is not None:
        try:
            issuccessful = list(issuccessful)
            if len(issuccessful) != len(data):
                issuccessful = None
        except TypeError:
            issuccessful = None

    # 3 & 4. Filtering Successful Data & Data Cleaning
    dat = [x for x in data if not np.isnan(x)]
    N = len(dat)

    if issuccessful is not None:
        issuccessful = [s for d, s in zip(data, issuccessful) if not np.isnan(d)]

    # 5. Empty Data Handling
    if N == 0:
        return (np.nan, np.nan, np.nan)

    # 6. Sorting Data
    dat.sort()

    # 7. Successful Data Filtering
    if issuccessful is not None:
        succdat = [d for d, s in zip(dat, issuccessful) if s]
    else:
        succdat = [d for d in dat if d < maxvalue]

    # 8. Success Rate Calculation
    succ = len(succdat) / N

    # 9. Result Calculation
    if succ == 0:
        res = np.inf if allowinf else sum(dat)
    else:
        res = sum(dat) / len(succdat)

    # 10. Return Statement
    return (res, succ, len(succdat))
```

