import numpy as np

def best_alg_indices(ert_ars, median_finalfunvals, datasets, targets):
    if ert_ars is None:
        ert_ars = np.array([dataset.detERT(targets) for dataset in datasets])

    best_indices = np.argsort(ert_ars, axis=0)

    for col_idx in range(ert_ars.shape[1]):
        if not np.all(np.isfinite(ert_ars[:, col_idx])):
            if median_finalfunvals is None:
                median_finalfunvals = np.array([np.median(dataset.finalfunvals) for dataset in datasets])
            best_indices[:, col_idx] = np.argsort(median_finalfunvals, axis=0)

    return best_indices
