import numpy as np

def draw_hill(x, y, a, b):
    x = np.array(x)
    y = np.array(y)

    def calc_loss(a0, b0, x, y):
        return np.sum((y - (a0 * x + b0)) ** 2) / (2 * len(x))

    allSSE = np.zeros((len(b), len(a)))
    for i, b0 in enumerate(b):
        for j, a0 in enumerate(a):
            allSSE[i, j] = calc_loss(a0, b0, x, y)

    A_grid, B_grid = np.meshgrid(a, b)
    return [A_grid, B_grid, allSSE]
```

