import numpy as np
from sklearn.metrics import precision_recall_fscore_support

def get_performance(y_true, y_pred, classes):
    precision, recall, f1, support = precision_recall_fscore_support(
        y_true, y_pred, labels=classes, zero_division=0
    )

    performance = {
        'overall': {
            'precision': float(np.mean(precision)),
            'recall': float(np.mean(recall)),
            'f1': float(np.mean(f1)),
            'num_samples': float(np.sum(support))
        },
        'class': {}
    }

    for i, cls in enumerate(classes):
        performance['class'][cls] = {
            'precision': float(precision[i]),
            'recall': float(recall[i]),
            'f1': float(f1[i]),
            'num_samples': float(support[i])
        }

    return performance
```

```python
import numpy as np

def logbins_numba(lo: float, hi: float, ratio: float, N: int, prepend_zero: bool) -> np.ndarray:
    lo = int(lo)
    hi = int(hi)

    if ratio != 0 and N == 0:
        N = int(np.log(hi / lo) / np.log(ratio))
    if N == 0:
        N = 10
    N = max(1, N)

    log_lo = np.log10(lo)
    log_hi = np.log10(hi)
    log_points = np.linspace(log_lo, log_hi, N)
    values = 10 ** log_points
    values = np.round(values).astype(int)

    values = np.unique(values)

    if len(values) == 0:
        return np.array([0]) if prepend_zero else np.array([], dtype=int)

    if values[0] != lo:
        values = np.insert(values, 0, lo)
    if values[-1] != hi:
        values = np.append(values, hi)

    if prepend_zero:
        values = np.insert(values, 0, 0)

    return values
```

```python
def qam_mod(M):
    sqrtM = int(M**0.5)
    special_cases = {
        8: (None, None),
        32: (None, None)
    }

    if M == 8:
        rows, cols = 4, 2
        x_vals_r = [-(rows - 1) + 2 * i for i in range(rows)]
        x_vals_c = [-(cols - 1) + 2 * i for i in range(cols)]
        map_table = {}
        demap_table = {}
        for i in range(M):
            r = i // cols
            c = i % cols
            gray = (r ^ (r >> 1)) * cols + (c ^ (c >> 1))
            point = x_vals_r[r] + 1j * x_vals_c[c]
            map_table[gray] = point
            demap_table[point] = gray
        return map_table, demap_table

    elif M == 32:
        rows, cols = 8, 4
        x_vals_r = [-(rows - 1) + 2 * i for i in range(rows)]
        x_vals_c = [-(cols - 1) + 2 * i for i in range(cols)]
        map_table = {}
        demap_table = {}
        for i in range(M):
            r = i // cols
            c = i % cols
            gray = (r ^ (r >> 1)) * cols + (c ^ (c >> 1))
            point = x_vals_r[r] + 1j * x_vals_c[c]
            map_table[gray] = point
            demap_table[point] = gray
        return map_table, demap_table

    else:
        x_vals = [-(sqrtM - 1) + 2 * i for i in range(sqrtM)]
        map_table = {}
        demap_table = {}
        for i in range(M):
            r = i // sqrtM
            c = i % sqrtM
            gray = (r ^ (r >> 1)) * sqrtM + (c ^ (c >> 1))
            point = x_vals[r] + 1j * x_vals[c]
            map_table[gray] = point
            demap_table[point] = gray
        return map_table, demap_table
