import numpy as np

def process_parameters_psd(dim, mean, cov):
    if dim is None:
        dim = 1

    if mean is not None:
        mean = np.array(mean, dtype=float)
        dim = mean.size
    elif cov is not None:
        cov = np.asarray(cov)
        if cov.ndim == 1:
            dim = 1
        else:
            dim = cov.shape[0] if cov.ndim > 0 else 1

    if mean is None:
        mean = np.zeros(dim)
    if cov is None:
        cov = 1.0

    if dim == 1:
        mean = mean.reshape(-1)
        cov_arr = np.asarray(cov)
        if cov_arr.ndim == 0:
            cov = cov_arr.reshape(1, 1)
        elif cov_arr.ndim == 1:
            cov = np.diag(cov_arr)

    cov = np.asarray(cov)
    if cov.ndim == 0:
        cov = cov * np.eye(dim)
    elif cov.ndim == 1:
        cov = np.diag(cov)
    elif cov.ndim == 2:
        if cov.shape != (dim, dim):
            if cov.shape[0] != cov.shape[1]:
                cov = np.eye(dim)
            else:
                cov = np.zeros((dim, dim))
    elif cov.ndim > 2:
        cov = np.eye(dim)

    return dim, mean, cov
```

