import numpy as np

def process_size_shape(size, r, c):
    shape = (len(r), len(c))
    if size is None:
        size = np.array([1])
    else:
        size = np.atleast_1d(size)
        if not (np.issubdtype(size.dtype, np.integer) and (size >= 0).all()):
            size = np.array([1])

    prod_size = int(np.prod(size))
    return prod_size, tuple(size) + shape
