import pandas as pd

def unmelt(df: pd.DataFrame) -> pd.DataFrame:
    if not isinstance(df, pd.DataFrame):
        return df

    if df.index.nlevels > 1:
        names = df.index.get_level_values(0).unique()
    else:
        names = df.index

    has_single_value_col = len(df.columns) == 1 and df.columns[0] == 'Value'

    if df.index.nlevels == 1:
        result = df.stack().dropna().T
    else:
        result = pd.concat([df.loc[name] for name in names], axis=1, keys=names)

    if has_single_value_col:
        if result.columns.nlevels > 1:
            result.columns = result.columns.droplevel(1)

    return result
