import pandas as pd

def melt(df):
    # 1. Check for Empty DataFrame
    if df.empty:
        return df

    # 2. Check DataFrame Type
    if not isinstance(df, pd.DataFrame):
        return df

    # 3. Handle MultiIndex Columns
    if isinstance(df.columns, pd.MultiIndex):
        names = df.columns.names[0]
        flat_idx = False
    else:
        flat_idx = True
        names = df.columns.tolist()

    # 4. Check for Column Names
    if not names:
        return df

    # 5. Concatenate DataFrame
    try:
        concatenated = pd.concat([df[col] for col in df.columns], keys=names, names=['Metric'])
    except ValueError:
        # 6. Handle ValueError
        return df

    # 7. Create New DataFrame
    df = pd.DataFrame(concatenated)

    # 8. Rename Columns for Flat Index
    if flat_idx:
        df.columns = ['Value']

    # 9. Remove Empty Levels
    df = remove_empty_level(df)
    return df

def remove_empty_level(df):
    # Helper function to remove index levels that are completely empty or all NaN
    for level in df.index.names:
        if level is not None and df.index.get_level_values(level).isna().all():
            df = df.droplevel(level)
    return df
