```python
import pandas as pd
from typing import Tuple

def split_train_test_vec(data: pd.DataFrame, split: float) -> Tuple[pd.DataFrame, pd.DataFrame]:
    train = pd.DataFrame()
    test = pd.DataFrame()

    unique_cats = data['Category_id'].unique()

    for cat in unique_cats:
        cat_data = data[data['Category_id'] == cat].copy()
        cat_data['Date'] = pd.to_datetime(cat_data['Date'])

        min_date = cat_data['Date'].min()
        max_date = cat_data['Date'].max()
        diff_days = (max_date - min_date).days + 1

        cutoff_date = min_date + pd.Timedelta(days=diff_days * split)

        cat_data['cutoff'] = (cat_data['Date'] > cutoff_date).astype(float)

        train_cat = cat_data[cat_data['cutoff'] == 0]
        test_cat = cat_data[cat_data['cutoff'] == 1]

        if not train_cat.empty:
            train = pd.concat([train, train_cat], ignore_index=True)
        if not test_cat.empty:
            test = pd.concat([test, test_cat], ignore_index=True)

    if not train.empty:
        train_counts = train['Category_id'].value_counts()
        mode_train = train_counts.mode()[0] if not train_counts.empty else 0

        def balance_train(group):
            if len(group) > mode_train:
                return group.tail(mode_train)
            return group

        train = train.groupby('Category_id', group_keys=False).apply(balance_train)

    if not test.empty:
        test_counts = test['Category_id'].value_counts()
        mode_test = test_counts.mode()[0] if not test_counts.empty else 0

        def balance_test(group):
            if len(group) > mode_test:
                return group.head(mode_test)
            return group

        test = test.groupby('Category_id', group_keys=False).apply(balance_test)

    return train, test
```

```python
import pandas as pd

def _calc_inverse_distance(dist_df, k):
    inv_dist = dist_df.iloc[:, :k] ** -1.0
    return inv_dist.div(inv_dist.sum(axis=1), axis=0)

def _normalize_rows(df):
    return df.div(df.sum(axis=1), axis=0)

def _calc_idw_weighted_score(knn_pred_dist, knn_pred_class, k, classes):
    inv_dist = _calc_inverse_distance(knn_pred_dist + 1, k)
    l = []
    for e in classes:
        mask = (knn_pred_class == e).astype(int)
        weighted = mask * inv_dist
        l.append(weighted.sum(axis=1))
    ws = pd.DataFrame(l).T
    ws.columns = classes
    wsn = _normalize_rows(ws)
    return wsn
```

```python
import pandas as pd

def describe_numeric_aggregate(stats, name=None, is_timedelta_col=False, is_datetime_col=False, unit='ns'):
    count, mean, std, min_val, q, max_val = stats

    if is_timedelta_col:
        mean = pd.to_timedelta(mean, unit=unit)
        std = pd.to_timedelta(std, unit=unit)
        min_val = pd.to_timedelta(min_val, unit=unit)
        max_val = pd.to_timedelta(max_val, unit=unit)
        if isinstance(q, pd.Series):
            q = q.apply(lambda x: pd.to_timedelta(x, unit=unit))
        else:
            q = pd.Series(q, index=['25%', '50%', '75%']).apply(lambda x: pd.to_timedelta(x, unit=unit))
    elif is_datetime_col:
        min_val = pd.to_datetime(min_val, unit=unit)
        max_val = pd.to_datetime(max_val, unit=unit)
        if isinstance(q, pd.Series):
            q = q.apply(lambda x: pd.to_datetime(x, unit=unit))
        else:
            q = pd.Series(q, index=['25%', '50%', '75%']).apply(lambda x: pd.to_datetime(x, unit=unit))

    if is_datetime_col:
        part1 = pd.Series({'count': count, 'min': min_val})
    else:
        part1 = pd.Series({'count': count, 'mean': mean, 'std': std, 'min': min_val})

    if isinstance(q, pd.Series):
        q_series = q.copy()
        q_series.index = [f'{x*100:.0f}%' for x in q_series.index]
    else:
        q_series = pd.Series(q, index=['25%', '50%', '75%'])

    part3 = pd.Series({'max': max_val})

    result = pd.concat([part1, q_series, part3])

    if name is not None:
        result.name = name

    return result
```

