import pandas as pd

def cat_var(data, col_excl=None, return_cat=True):
    df = data.copy()

    # Identify non-numeric columns
    numeric_cols = df.select_dtypes(include='number').columns
    non_numeric_cols = [col for col in df.columns if col not in numeric_cols]

    # Exclude specified columns if provided
    if col_excl is not None:
        non_numeric_cols = [col for col in non_numeric_cols if col not in col_excl]

    # Create DataFrame for categorical variables with indices and names
    cat_var_df = pd.DataFrame({
        'cat_ind': [df.columns.get_loc(col) for col in non_numeric_cols],
        'cat_name': non_numeric_cols
    }).sort_values('cat_ind', ascending=False).reset_index(drop=True)

    # Convert date columns to string
    date_cols = [col for col in non_numeric_cols if 'date' in col.lower()]
    df[date_cols] = df[date_cols].astype(str)

    # Prepare mappers
    inv_mapper = {}
    mapper = {}

    for col in non_numeric_cols:
        unique_vals = sorted(df[col].dropna().unique())
        inv_mapper[col] = {i: val for i, val in enumerate(unique_vals)}
        mapper[col] = {val: i for i, val in enumerate(unique_vals)}

    # Map categorical values to integers, fill missing with 0
    for col in non_numeric_cols:
        df[col] = df[col].map(mapper[col]).fillna(0).astype(int)

    # Convert back to categorical types if requested
    if return_cat:
        df[non_numeric_cols] = df[non_numeric_cols].astype('category')

    return df, cat_var_df, inv_mapper, mapper
```

