```python
import pandas as pd
import numpy as np

def reduce_mem_usage(df):
    start_mem_usg = df.memory_usage(deep=True).sum() / 1024**2
    NAlist = []

    for col in df.columns:
        if df[col].dtype == 'object':
            continue

        col_min = df[col].min()
        col_max = df[col].max()

        # Handle NaN and Inf
        if df[col].isna().any() or np.isinf(df[col]).any():
            col_series = df[col]
            finite_min = col_series.dropna().min()
            if np.isfinite(finite_min):
                df[col] = col_series.fillna(finite_min)
            else:
                df[col] = col_series.fillna(0)
            df[col] = df[col].replace([np.inf, -np.inf], 0)
            NAlist.append(col)

            col_min = df[col].min()
            col_max = df[col].max()

        if np.issubdtype(df[col].dtype, np.floating):
            if np.sum(np.abs(df[col] - np.round(df[col]))) < 0.01:
                if col_min >= 0:
                    if col_max <= 255:
                        df[col] = df[col].astype(np.uint8)
                    elif col_max <= 65535:
                        df[col] = df[col].astype(np.uint16)
                    elif col_max <= 4294967295:
                        df[col] = df[col].astype(np.uint32)
                    else:
                        df[col] = df[col].astype(np.uint64)
                else:
                    if col_min >= np.iinfo(np.int8).min and col_max <= np.iinfo(np.int8).max:
                        df[col] = df[col].astype(np.int8)
                    elif col_min >= np.iinfo(np.int16).min and col_max <= np.iinfo(np.int16).max:
                        df[col] = df[col].astype(np.int16)
                    elif col_min >= np.iinfo(np.int32).min and col_max <= np.iinfo(np.int32).max:
                        df[col] = df[col].astype(np.int32)
                    else:
                        df[col] = df[col].astype(np.int64)
            else:
                df[col] = df[col].astype(np.float32)

    end_mem_usg = df.memory_usage(deep=True).sum() / 1024**2
    mem_usg_percentage = (start_mem_usg - end_mem_usg) / start_mem_usg * 100

    return df, NAlist, mem_usg_percentage
```

