import pandas as pd

def fix_missing(df: pd.DataFrame, col: pd.Series, name: str, na_dict: dict) -> dict:
    if pd.api.types.is_numeric_dtype(col):
        if pd.isnull(col).sum() > 0 or name in na_dict:
            df[name + '_na'] = pd.isnull(col)
            if name in na_dict:
                filler = na_dict[name]
            else:
                filler = col.median()
            df[name] = col.fillna(filler)
            na_dict[name] = filler
    return na_dict
