def _origins_from_cytoband(cyb: pd.DataFrame, band_col: str) -> pd.DataFrame:
    filtered = cyb[cyb[band_col] == 'acen']
    grouped = filtered.groupby('chrom', sort=False)
    cens = []
    for chrom, group in grouped:
        if len(group) != 2:
            return pd.DataFrame(cens)
        group = group.sort_values('start')
        cens.append({
            'chrom': chrom,
            'start': group.iloc[0]['start'],
            'end': group.iloc[1]['end'],
            'mid': group.iloc[0]['end']
        })
    return pd.DataFrame(cens)
