import pandas as pd
import random
from typing import Optional

def subsample_profiles(df: pd.DataFrame, rename_col: bool, subsampling_random_state: Optional[int], subsample_n: int, subsample_frac: float, linking_col_rename: Optional[dict]) -> pd.DataFrame:
    if subsampling_random_state is None:
        subsampling_random_state = random.randint(0, 10000)

    if subsample_frac == 1:
        sampled_df = df.sample(n=subsample_n, replace=True, random_state=subsampling_random_state)
    else:
        sampled_df = df.sample(frac=subsample_frac, random_state=subsampling_random_state)

    if rename_col and linking_col_rename is not None:
        sampled_df = sampled_df.rename(columns=linking_col_rename)

    return sampled_df
