import pandas as pd

def add_na_indicator(df: pd.DataFrame, replace_val_obj: str, replace_val_num: float) -> pd.DataFrame:
    na_cols = df.columns[df.isnull().any()].tolist()
    na_indicators = df[na_cols].isnull().rename(columns=lambda x: f'_is_na_{x}')

    categorical_cols = [c for c in df.columns if df[c].dtype.name == 'category']
    non_numeric_cols = [c for c in df.columns if df[c].dtype.name in ('object', 'string')]

    for col in na_cols:
        if replace_val_obj in df[col].unique():
            raise ValueError(f"replace_val_obj '{replace_val_obj}' already exists in column '{col}'")
        if col in categorical_cols:
            df[col] = df[col].cat.add_categories(replace_val_obj)
            df[col] = df[col].fillna(replace_val_obj)
        elif col in non_numeric_cols:
            df[col] = df[col].fillna(replace_val_obj)
        else:
            df[col] = df[col].fillna(replace_val_num)

    return pd.concat([df, na_indicators], axis=1)
