def add_event_window(df, time_col, label_col, time_delta, pre_num, post_num, events_name):
    pd_time_delta = pd.Timedelta(time_delta)
    df_dict = {}

    for num in range(pre_num):
        df_dict[f"{events_name}_minus_{num + 1}"] = pd.DataFrame({
            time_col: df[time_col] - (num + 1) * pd_time_delta,
            label_col: df[label_col]
        })

    for num in range(post_num):
        df_dict[f"{events_name}_plus_{num + 1}"] = pd.DataFrame({
            time_col: df[time_col] + (num + 1) * pd_time_delta,
            label_col: df[label_col]
        })

    return df_dict
