import pandas as pd
from collections import defaultdict

def generate_ngrams(sentence, n_gram, stopwords):
    words = sentence.split()
    filtered_words = [w for w in words if w not in stopwords]
    return [" ".join(filtered_words[i:i+n_gram]) for i in range(len(filtered_words) - n_gram + 1)]

def generate_freq_df(value, n_gram, top_n, stopwords, verbose):
    freq_dict = defaultdict(int)

    if verbose:
        pass

    for sentence in value:
        for ngram in generate_ngrams(sentence, n_gram, stopwords):
            freq_dict[ngram] += 1

    df = pd.DataFrame(list(freq_dict.items()), columns=['word', 'word_count'])
    df = df.sort_values(by='word_count', ascending=False).reset_index(drop=True)

    return df.head(top_n)
```

