import pandas as pd

def append_df_symbol(df: pd.DataFrame, symbol_name: str, overwrite: bool, symbols: list, data_d: pd.DataFrame) -> pd.DataFrame:
    def remove_symbol(data_d, symbol_name):
        mask = data_d.columns.get_level_values(0) != symbol_name
        return data_d.loc[:, mask]

    if symbol_name in symbols:
        if overwrite:
            data_d = remove_symbol(data_d, symbol_name)
        else:
            return data_d

    df = df.copy()

    if not data_d.empty and isinstance(data_d.columns, pd.MultiIndex):
        existing_fields = data_d.columns.get_level_values(1).unique()
    else:
        existing_fields = df.columns

    if len(existing_fields) > 0:
        missing_fields = [f for f in existing_fields if f not in df.columns]
        if missing_fields:
            df2 = pd.DataFrame(index=df.index, columns=existing_fields, dtype=float)
            df2.update(df)
            df = df2

    df.columns = pd.MultiIndex.from_product([[symbol_name], df.columns])

    if data_d.empty:
        data_d = df
    else:
        data_d = data_d.join(df, how='left')

    if symbol_name not in symbols:
        symbols.append(symbol_name)

    return data_d
```

