def apply_and_concat(df, fields, func, column_names, func_args):
    d = {name: [] for name in column_names}
    for _, row in df.iterrows():
        row_values = row[fields]
        res = func(row_values, *func_args)
        for i, col_name in enumerate(column_names):
            d[col_name].append(res[i])
    df2 = pd.DataFrame(d, index=df.index)
    return pd.concat([df, df2], axis=1, sort=True)
