```python
def rank_with_mask(df, axis, mask, normalize, method):
    not_nan_mask = ~df.isnull()
    if mask is None:
        mask = not_nan_mask
    else:
        mask = mask & not_nan_mask

    ranks = df[mask].rank(axis=axis, na_option='keep', method=method)

    if normalize:
        dividend = ranks.max(axis=axis)
        ranks = (ranks - 1) / (dividend - 1)

    return ranks
```

```python
def stratified_group_shuffle_split(df_main, train_proportion, val_proportion,
                                   hparam_mse_wgt, df_group, y_var):
    random_state = 42
    df_shuffled = df_main.sample(frac=1, random_state=random_state).reset_index(drop=True)

    train_df = pd.DataFrame(columns=df_main.columns)
    val_df = pd.DataFrame(columns=df_main.columns)
    test_df = pd.DataFrame(columns=df_main.columns)

    test_proportion = 1 - train_proportion - val_proportion

    groups = df_shuffled.groupby(df_group)
    expected_dist = df_main[y_var].value_counts(normalize=True).sort_index()

    def calc_mse_loss(df_sub):
        if df_sub.empty:
            return float('inf')
        actual_dist = df_sub[y_var].value_counts(normalize=True).sort_index()
        actual_dist = actual_dist.reindex(expected_dist.index, fill_value=0.0)
        return ((expected_dist - actual_dist) ** 2).mean()

    group_names = list(groups.groups.keys())

    for i, group_name in enumerate(group_names):
        group_data = groups.get_group(group_name)

        if i < 3:
            if i == 0:
                train_df = pd.concat([train_df, group_data], ignore_index=True)
            elif i == 1:
                val_df = pd.concat([val_df, group_data], ignore_index=True)
            else:
                test_df = pd.concat([test_df, group_data], ignore_index=True)
        else:
            mse_train = calc_mse_loss(train_df)
            size_train = abs(len(train_df) / len(df_shuffled) - train_proportion)
            loss_train = hparam_mse_wgt * mse_train + (1 - hparam_mse_wgt) * size_train

            mse_val = calc_mse_loss(val_df)
            size_val = abs(len(val_df) / len(df_shuffled) - val_proportion)
            loss_val = hparam_mse_wgt * mse_val + (1 - hparam_mse_wgt) * size_val

            mse_test = calc_mse_loss(test_df)
            size_test = abs(len(test_df) / len(df_shuffled) - test_proportion)
            loss_test = hparam_mse_wgt * mse_test + (1 - hparam_mse_wgt) * size_test

            losses = {'train': loss_train, 'val': loss_val, 'test': loss_test}
            best_split = min(losses, key=losses.get)

            if best_split == 'train':
                train_df = pd.concat([train_df, group_data], ignore_index=True)
            elif best_split == 'val':
                val_df = pd.concat([val_df, group_data], ignore_index=True)
            else:
                test_df = pd.concat([test_df, group_data], ignore_index=True)

    return train_df, val_df, test_df
```

