```python
import math
from scipy import stats

def preprocess_data(data):
    cleaned = []
    for x in data:
        try:
            val = float(x)
            if not math.isnan(val):
                cleaned.append(val)
        except (ValueError, TypeError):
            pass

    if len(cleaned) > 1:
        mean = sum(cleaned) / len(cleaned)
        std_dev = (sum((x - mean)**2 for x in cleaned) / len(cleaned)) ** 0.5
        lower = mean - 3 * std_dev
        upper = mean + 3 * std_dev
        cleaned = [x for x in cleaned if lower <= x <= upper]
    return cleaned

def interpret_result(statistic, p_value, alpha):
    if p_value < alpha:
        return f'Significant difference between distributions (p={p_value:.5f}, KS stat={statistic:.5f})'
    else:
        return f'No significant difference between distributions (p={p_value:.5f}, KS stat={statistic:.5f})'

def test_nametuples_agree(data1, data2):
    alpha = 0.05
    data1_clean = preprocess_data(data1)
    data2_clean = preprocess_data(data2)

    if len(data1_clean) < 2 or len(data2_clean) < 2:
        return "Insufficient data after preprocessing."

    statistic, p_value = stats.kstest(data1_clean, data2_clean)
    return interpret_result(statistic, p_value, alpha)
```

