import numpy as np
import scipy.stats as stats

def test_tmax(data):
    results = {}

    if len(data) == 0:
        results['error'] = 'Empty array provided'
        return results

    x = np.array(data)

    if np.all(np.isnan(x)):
        results['error'] = 'All values are NaN'
        return results

    try:
        results['single_value'] = stats.tmax(x)
        results['full_array'] = stats.tmax(x)

        finite_vals = x[np.isfinite(x)]
        if len(finite_vals) > 0:
            max_x = np.max(finite_vals)
        else:
            max_x = None

        if max_x is not None:
            results['upperlimit_max'] = stats.tmax(x, upperlimit=max_x)

        if max_x is not None and np.any(x < max_x):
            results['upperlimit_max_exclusive'] = stats.tmax(x, upperlimit=max_x, upperlimit_exclusive=True)

        if x.ndim == 1 and len(x) > 1:
            x_2d = x.reshape(-1, 2)
            results['axis_1'] = stats.tmax(x_2d, axis=1)

        results['axis_none'] = stats.tmax(x, axis=None)

        if np.any(np.isnan(x)):
            results['nan_policy_omit'] = stats.tmax(x, nan_policy='omit')

    except ValueError as e:
        results['error'] = str(e)

    return results
```

