import numpy as np
import numpy.ma as ma
from scipy.stats import mstats

def compute_ranking(data, mask_indices, axis, use_missing):
    x = ma.array(np.atleast_1d(data))
    if mask_indices is not None:
        for idx in mask_indices:
            x[idx] = ma.masked

    if x.size == 0:
        return np.array([])

    if ma.is_masked(x) and x.mask.all():
        return np.full(x.shape, np.nan)

    if x.ndim == 1:
        axis = 0

    try:
        result = mstats.rankdata(x, axis=axis, use_missing=use_missing)
        return result
    except TypeError:
        return np.full(x.shape, np.nan)
