```python
import numpy as np
import scipy.sparse as sparse

def make_system(A, x, b, formats=None):
    # Format Handling
    if formats is not None:
        target_fmt = formats[0]
        if sparse.issparse(A):
            if hasattr(A, 'to' + target_fmt):
                A = getattr(A, 'to' + target_fmt)()
            elif hasattr(A, 'to' + target_fmt.upper()):
                A = getattr(A, 'to' + target_fmt.upper())()
        else:
            A = sparse.csr_matrix(A)
            if hasattr(A, 'to' + target_fmt):
                A = getattr(A, 'to' + target_fmt)()

    # Matrix Shape Validation
    M, N = A.shape
    if M != N:
        A = sparse.eye(M, format='csr')

    # Vector Conversion
    x = np.asarray(x)
    b = np.asarray(b)

    # Vector Reshaping
    if x.shape == (M, 1) or x.shape == (M,):
        x = x.flatten()
    else:
        x = np.zeros(M)

    if b.shape == (M, 1) or b.shape == (M,):
        b = b.flatten()
    else:
        b = np.ones(M)

    # Data Type Consistency
    if A.dtype != x.dtype or x.dtype != b.dtype:
        dtype = np.float64
        A = A.astype(dtype)
        x = x.astype(dtype)
        b = b.astype(dtype)

    return A, x, b
