import scipy.stats

def get_distributions(filter_keyword: str, max_results: int, format_output: bool) -> dict:
    discovered_distributions = list(scipy.stats._continuous_distnames) + list(scipy.stats._discrete_distnames)

    def preprocess(name):
        name = name.strip()
        if format_output:
            name = name.lower().replace('_', '-')
        return name

    cleaned = [preprocess(name) for name in discovered_distributions]

    if filter_keyword:
        kw = filter_keyword.lower()
        cleaned = [name for name in cleaned if kw in name]

    total_found = len(cleaned)

    if max_results > 0:
        preview = cleaned[:max_results]
    else:
        preview = cleaned

    full_list = list(preview)
    if total_found > max_results and max_results > 0:
        full_list.append("...")

    return {
        "total_distributions_found": total_found,
        "preview": preview,
        "full_list": full_list
    }
