```python
import numpy as np
from typing import Union, Tuple

def savitzky_golay2d(z: np.ndarray, window: int, order: int, deriv: Union[None, int, str]) -> Union[np.ndarray, Tuple[np.ndarray, np.ndarray]]:
    half_size = window // 2

    # Generate exponents for polynomial terms
    exps = []
    for i in range(order + 1):
        for j in range(order + 1 - i):
            exps.append((i, j))

    # Create indices and coordinate grids
    ind = np.arange(-half_size, half_size + 1)
    dx, dy = np.meshgrid(ind, ind)

    # Prepare and fill convolution matrix A
    A = np.zeros((window * window, len(exps)))
    for k, (i, j) in enumerate(exps):
        A[:, k] = (dx**i * dy**j).ravel()

    # Pad input array with edge values
    Z = np.pad(z, half_size, mode='edge')

    # Compute polynomial coefficients using pseudo-inverse
    coeffs = np.linalg.pinv(A)

    # Identify indices for smoothing and derivatives
    idx_smooth = 0
    idx_row = exps.index((0, 1)) if (0, 1) in exps else -1
    idx_col = exps.index((1, 0)) if (1, 0) in exps else -1

    # Helper to apply a kernel to the padded array
    def apply_kernel(kernel, out_shape):
        h, w = kernel.shape
        out = np.zeros(out_shape)
        for i in range(h):
            for j in range(w):
                out += kernel[i, j] * Z[i:i+out_shape[0], j:j+out_shape[1]]
        return out

    # Handle derivative options
    if deriv in [None, 0]:
        kernel = coeffs[idx_smooth].reshape(window, window)
        return apply_kernel(kernel, z.shape)
    elif deriv in [1, 'both']:
        k_row = coeffs[idx_row].reshape(window, window) if idx_row != -1 else np.zeros((window, window))
        k_col = coeffs[idx_col].reshape(window, window) if idx_col != -1 else np.zeros((window, window))
        return apply_kernel(k_row, z.shape), apply_kernel(k_col, z.shape)
    elif deriv in [2, 'col']:
        kernel = coeffs[idx_col].reshape(window, window) if idx_col != -1 else np.zeros((window, window))
        return apply_kernel(kernel, z.shape)
    elif deriv in [3, 'row']:
        kernel = coeffs[idx_row].reshape(window, window) if idx_row != -1 else np.zeros((window, window))
        return apply_kernel(kernel, z.shape)
    else:
        raise ValueError("Invalid deriv parameter")
```

