import numpy as np
import scipy.stats as sps

def fit(spsdotwhat, x, fwords):
    x = np.asarray(x)
    if len(np.unique(x)) < 2:
        return None

    if hasattr(spsdotwhat, 'fit'):
        try:
            shape_loc_scale = spsdotwhat.fit(x, **fwords)
        except Exception:
            shape_loc_scale = (np.nan, np.nan, np.nan)
    else:
        shape_loc_scale = (np.nan, np.nan, np.nan)

    def check_shape_loc_scale(params, dist):
        if np.any(np.isnan(params)) or np.any(np.isinf(params)):
            return False
        name = dist.name
        if name == 'norm':
            if params[-1] <= 0:
                return False
        elif name in ('weibull_min', 'gamma', 'rice'):
            if params[0] <= 0 or params[-1] <= 0:
                return False
        elif name == 'beta':
            if params[0] <= 0 or params[1] <= 0 or params[0] > 1e10 or params[1] > 1e10:
                return False
        return True

    if not check_shape_loc_scale(shape_loc_scale, spsdotwhat):
        if spsdotwhat.name == 'gamma':
            mean = np.mean(x)
            var = np.var(x)
            if var == 0:
                return None
            shape = mean**2 / var
            scale = var / mean
            shape_loc_scale = (shape, 0, scale)
        elif spsdotwhat.name == 'beta':
            x_min, x_max = np.min(x), np.max(x)
            if x_min == x_max:
                return None
            x_norm = (x - x_min) / (x_max - x_min)
            x_norm = np.clip(x_norm, 1e-10, 1 - 1e-10)
            mean = np.mean(x_norm)
            var = np.var(x_norm)
            if var == 0:
                return None
            p = mean * (mean * (1 - mean) / var - 1)
            q = p * (1 - mean) / mean
            shape_loc_scale = (p, q, 0, 0)

    if not check_shape_loc_scale(shape_loc_scale, spsdotwhat):
        return None

    try:
        stat, _ = sps.kstest(x, spsdotwhat, args=shape_loc_scale)
        if stat > 0.5:
            return None
    except Exception:
        return None

    return shape_loc_scale
```

