```python
import numpy as np
import torch
from scipy import signal

def scaling(sig):
    factor = np.random.normal(1.0, 0.05, size=(1, sig.shape[1]))
    return sig * factor

def verflip(sig):
    return sig[::-1, :]

def shift(sig):
    interval = 20
    offset = np.random.uniform(-interval/100, interval/100, size=(1, sig.shape[1]))
    return sig + offset

def butter_bandpass_filter(sig):
    lowcut = 0.05
    highcut = 46
    fs = 256
    nyq = 0.5 * fs
    low = lowcut / nyq
    high = highcut / nyq
    b, a = signal.butter(4, [low, high], btype='band')
    return signal.filtfilt(b, a, sig, axis=0)

def transform(sig, operation_list):
    for op in operation_list:
        if op == 'scaling':
            sig = scaling(sig)
        elif op == 'verflip':
            sig = verflip(sig)
        elif op == 'shift':
            sig = shift(sig)
        elif op == 'butter_bandpass_filter':
            sig = butter_bandpass_filter(sig)

    sig = sig.T
    return torch.tensor(sig, dtype=torch.float32)
```

