import scipy.stats
from scipy.stats import rv_continuous

popular_names = ['norm', 'uniform', 'expon', 'gamma', 'beta', 'cauchy', 'lognorm', 'weibull_min', 'pareto']

def get_distributions(distr, k_distribution):
    out_distr = []
    if isinstance(distr, list):
        for item in distr:
            if item == 'k':
                out_distr.append(k_distribution)
            else:
                dist = getattr(scipy.stats, item, None)
                if dist is not None:
                    out_distr.append(dist)
    elif distr == 'full':
        out_distr = [getattr(scipy.stats, name) for name in dir(scipy.stats) if isinstance(getattr(scipy.stats, name), rv_continuous)]
    elif distr == 'popular':
        for name in popular_names:
            dist = getattr(scipy.stats, name, None)
            if dist is not None:
                out_distr.append(dist)
    else:
        dist = getattr(scipy.stats, distr, None)
        if dist is not None:
            out_distr.append(dist)
    return out_distr
