```python
import numpy as np

def _contains_nan(arr, nan_policy):
    return np.isnan(arr).any()

def percentileofscore(a, score, kind, nan_policy):
    a = np.asarray(a)
    score = np.asarray(score)
    original_shape = score.shape

    a_nan = _contains_nan(a, nan_policy)
    score_nan = _contains_nan(score, nan_policy)

    if nan_policy == 'propagate':
        if a_nan or score_nan:
            return np.full(original_shape, np.nan)

    if nan_policy == 'omit':
        if a_nan:
            a = a[~np.isnan(a)]

    n = len(a)
    if n == 0:
        return np.full(original_shape, np.nan)

    score_mask = np.zeros(original_shape, dtype=bool)
    if nan_policy == 'omit' and score_nan:
        score_mask = np.isnan(score)
        valid_score = score[~score_mask]
    else:
        valid_score = score

    # Reshape score to ensure broadcasting against a
    valid_score = valid_score.reshape(-1, 1)
    a_expanded = a[:, np.newaxis]

    counts_less = np.sum(a_expanded < valid_score, axis=0)
    counts_less_eq = np.sum(a_expanded <= valid_score, axis=0)
    counts_equal = np.sum(a_expanded == valid_score, axis=0)

    if kind == 'strict':
        res = counts_less / n * 100.0
    elif kind == 'weak':
        res = counts_less_eq / n * 100.0
    elif kind == 'rank':
        res = (counts_less + 0.5 * counts_equal) / n * 100.0
    elif kind == 'mean':
        rank_val = (counts_less + 0.5 * counts_equal) / n * 100.0
        strict_val = counts_less / n * 100.0
        res = (rank_val + strict_val) / 2.0
    else:
        res = np.full_like(valid_score, np.nan)

    result = np.full(original_shape, np.nan)
    result.flat[~score_mask] = res

    if result.ndim == 0:
        return float(result)
    return result
```

