import pandas as pd
import numpy as np
from lightgbm import LGBMClassifier, LGBMRegressor
from sklearn.preprocessing import MinMaxScaler

def analyze_problem_type(y):
    n_unique = y.nunique()
    if n_unique <= 2:
        return 'binary'
    elif n_unique > 2:
        return 'multiclass'
    else:
        return 'regression'

def simple_model(X_train, y_train, X_test):
    # Convert y_train to Series if it's a NumPy array
    if isinstance(y_train, np.ndarray):
        y_train = pd.Series(y_train, index=X_train.index)

    # Determine problem type
    problem_type = analyze_problem_type(y_train)

    # Set base model parameters based on problem type
    if problem_type == 'regression':
        model_params = {}
    elif problem_type == 'binary':
        model_params = {'objective': 'binary'}
    else:
        model_params = {'objective': 'multiclass'}

    # Update with common parameters
    model_params.update({
        'boosting_type': 'gbdt',
        'verbose': -1,
        'seed': 42,
        'feature_fraction': 0.8,
        'bagging_fraction': 0.8,
        'max_depth': 6,
        'n_estimators': 100,
        'num_leaves': 31,
        'min_data_in_leaf': 20,
        'subsample_freq': 1
    })

    # Handle classification-specific parameters
    if problem_type != 'regression':
        n_classes = y_train.nunique()
        model_params['num_class'] = n_classes if n_classes > 2 else 1
        model_params['is_unbalance'] = True

    # Initialize model
    if problem_type == 'regression':
        model = LGBMRegressor(**model_params)
    else:
        model = LGBMClassifier(**model_params)

    # Train model
    model.fit(X_train, y_train)

    # Make predictions
    preds = model.predict(X_test)

    probs = None
    if problem_type != 'regression':
        probs = model.predict_proba(X_test)
        # Scale probabilities to [0, 1]
        probs = MinMaxScaler().fit_transform(probs)

    return preds, probs
