import numpy as np
from sklearn.metrics import accuracy_score, precision_score, recall_score

def preprocess_data(y_true, y_pred, mode):
    if mode == 'binary':
        y_true_proc = (y_true >= 0).astype(int)
        y_pred_proc = (y_pred >= 0).astype(int)
    else:
        y_true_proc = y_true
        y_pred_proc = np.argmax(y_pred, axis=1) if y_pred.ndim > 1 else y_pred
    return y_true_proc, y_pred_proc

def interpret_fate(y_true_proc, y_pred_proc):
    acc = accuracy_score(y_true_proc, y_pred_proc)
    prec = precision_score(y_true_proc, y_pred_proc, zero_division=0)
    rec = recall_score(y_true_proc, y_pred_proc, zero_division=0)
    return {"accuracy": acc, "precision": prec, "recall": rec}

def reveal_truth(y_true, y_pred, train_config=None):
    if train_config is not None and getattr(train_config, 'data', None) == 'ur_funny':
        prophecy_mode = 'multi-class'
    else:
        prophecy_mode = 'binary'

    y_true_proc, y_pred_proc = preprocess_data(y_true, y_pred, prophecy_mode)
    return interpret_fate(y_true_proc, y_pred_proc)
