import numpy as np
from sklearn.tree import DecisionTreeClassifier, DecisionTreeRegressor
from sklearn.model_selection import KFold, cross_val_score, ParameterGrid, ParameterSampler

def grid_search_with_multioutput_data(X, y):
    est_parameters = {'max_depth': list(range(1, 5))}

    # Determine task type
    if np.ndim(y) == 1:
        n_unique = len(np.unique(y))
    else:
        n_unique = len(np.unique(y.argmax(axis=1)))

    if n_unique < 10:
        if np.ndim(y) > 1:
            y = y.argmax(axis=1)
        Estimator = DecisionTreeClassifier
    else:
        Estimator = DecisionTreeRegressor

    cv = KFold(n_splits=5, shuffle=False, random_state=None)
    results = {}

    # Grid Search
    param_grid = list(ParameterGrid(est_parameters))
    grid_scores = {}
    for i, params in enumerate(param_grid):
        est = Estimator(**params)
        scores = cross_val_score(est, X, y, cv=cv, scoring=None)
        grid_scores[f'candidate_{i}'] = scores.tolist()
    results[f'GridSearch_{Estimator.__name__}'] = grid_scores

    # Randomized Search
    param_samples = list(ParameterSampler(est_parameters, n_iter=3, random_state=42))
    random_scores = {}
    for i, params in enumerate(param_samples):
        est = Estimator(**params)
        scores = cross_val_score(est, X, y, cv=cv, scoring=None)
        random_scores[f'candidate_{i}'] = scores.tolist()
    results[f'RandomSearch_{Estimator.__name__}'] = random_scores

    return results
