```python
import numpy as np
import pandas as pd
from sklearn.ensemble import RandomForestRegressor
from sklearn.svm import SVR
from sklearn.neighbors import KNeighborsRegressor

def machine_regression(X_train, y_train, X_test, y_test):
    scores = []

    y_train = np.asarray(y_train)
    y_test = np.asarray(y_test)

    # Shape Adjustment
    if y_train.ndim == 3:
        y_train = y_train.squeeze(axis=-1)
    if y_test.ndim == 3:
        y_test = y_test.squeeze(axis=-1)

    # Initialize models
    models = {
        "GCN+rf": RandomForestRegressor(),
        "GCN+svm": SVR(C=0.8),
        "GCN+knn": KNeighborsRegressor()
    }

    # Ensure y_test is 2D for consistent shape checking
    if y_test.ndim == 1:
        y_test = y_test.reshape(-1, 1)

    # Single Output Case
    if y_test.shape[-1] == 1:
        for name, model in models.items():
            model.fit(X_train, y_train)
            y_pred = model.predict(X_test)
            rmse = np.sqrt(np.mean((y_test - y_pred)**2))
            scores.append((name, rmse))
    else:
        # Multi-Output Case
        results = {name: [] for name in models}
        for i in range(y_test.shape[-1]):
            if np.max(y_train[:, i]) == 0 or np.max(y_test[:, i]) == 0:
                continue
            for name, model in models.items():
                model.fit(X_train, y_train[:, i])
                y_pred = model.predict(X_test)
                rmse = np.sqrt(np.mean((y_test[:, i] - y_pred)**2))
                results[name].append(rmse)

        for name in models:
            if results[name]:
                scores.append((name, np.mean(results[name])))

    if scores:
        return pd.DataFrame(scores, columns=["Model", "RMSE"])
    return pd.DataFrame(columns=["Model", "RMSE"])
```

