import numpy as np
from sklearn.metrics import (
    adjusted_rand_score,
    homogeneity_score,
    adjusted_mutual_info_score,
    fowlkes_mallows_score,
    contingency_matrix
)

def externalValidation(truthClusters, predictedClusters):
    def purity_score(truth, predicted):
        cont_matrix = contingency_matrix(truth, predicted)
        return np.sum(np.max(cont_matrix, axis=0)) / len(truth)

    return {
        'rand_index': adjusted_rand_score(truthClusters, predictedClusters),
        'homogeneity_score': homogeneity_score(truthClusters, predictedClusters),
        'purity_score': purity_score(truthClusters, predictedClusters),
        'adjusted_mutual_info_score': adjusted_mutual_info_score(truthClusters, predictedClusters),
        'fowlkes_mallows_score': fowlkes_mallows_score(truthClusters, predictedClusters)
    }
