from sklearn.linear_model import LogisticRegression
from sklearn.ensemble import RandomForestClassifier, VotingClassifier
from sklearn.naive_bayes import GaussianNB
from sklearn.model_selection import cross_val_score

def ensemble_model(train_data, train_target):
    classifiers = {
        'Logistic Regression': LogisticRegression(solver='lbfgs'),
        'Random Forest': RandomForestClassifier(n_estimators=50),
        'Naive Bayes': GaussianNB()
    }

    # Convert names to lowercase and replace spaces with underscores for the ensemble
    ensemble_estimators = [
        (name.lower().replace(' ', '_'), clf) for name, clf in classifiers.items()
    ]
    ensemble = VotingClassifier(estimators=ensemble_estimators)

    results = {}
    cv = 5

    for name, clf in classifiers.items():
        scores = cross_val_score(clf, train_data, train_target, cv=cv, scoring='accuracy')
        results[name] = {
            'mean_accuracy': scores.mean(),
            'std_accuracy': scores.std()
        }

    ensemble_scores = cross_val_score(ensemble, train_data, train_target, cv=cv, scoring='accuracy')
    results['Ensemble'] = {
        'mean_accuracy': ensemble_scores.mean(),
        'std_accuracy': ensemble_scores.std()
    }

    return results
```

