def get_scaler(param):
    transformers = {
        "quantile": QuantileTransformer(output_distribution="normal"),
        "maxabs": MaxAbsScaler(),
        "robust": RobustScaler(),
        "minmax": MinMaxScaler(),
        "yeo-johnson": PowerTransformer(method="yeo-johnson"),
        "box_cox": PowerTransformer(method="box-cox"),
        "standard": StandardScaler(),
        "l2": Normalizer(norm="l2"),
        "kbins_discretizer": KBinsDiscretizer(n_bins=10, encode="ordinal", strategy="uniform")
    }

    transformer_name = param.get("transformer")
    if transformer_name in transformers:
        return transformers[transformer_name]
    else:
        n_quantiles = param.get("n_quantiles", 1000)
        return QuantileTransformer(n_quantiles=n_quantiles)
