import numpy as np

def check_consistent_length(*arrays):
    lengths = [len(arr) for arr in arrays]
    if len(set(lengths)) != 1:
        raise ValueError("Input arrays must have the same length.")

def indexable(*iterables):
    return list(iterables)

def _num_samples(x):
    return len(x)

def size_to_number(size, n_samples):
    if size is None:
        return None
    if isinstance(size, (int, np.integer)):
        return size
    if isinstance(size, float):
        return int(size * n_samples)
    raise ValueError("Invalid size type")

def _safe_indexing(x, idx):
    return x[idx]

def gap_train_test_split(arrays, options):
    if not arrays:
        return []

    check_consistent_length(*arrays)

    test_size = options.get('test_size', None)
    train_size = options.get('train_size', None)
    gap_size = options.get('gap_size', 0)

    arrays = indexable(*arrays)

    n_samples = _num_samples(arrays[0])

    n_gap = size_to_number(gap_size, n_samples)

    if test_size is None and train_size is None:
        test_size = 0.25

    n_test = size_to_number(test_size, n_samples)
    n_train = size_to_number(train_size, n_samples)

    if n_train is None:
        n_train = n_samples - n_gap - n_test
    if n_test is None:
        n_test = n_samples - n_gap - n_train

    train_indices = range(n_train)
    test_indices = range(n_train + n_gap, n_samples)

    result = []
    for arr in arrays:
        result.append(_safe_indexing(arr, train_indices))
        result.append(_safe_indexing(arr, test_indices))

    return result
```

