import pandas as pd
from sklearn.model_selection import cross_validate

def _cross_validate(model, X_train, y_train):
    if model.estimator_type == 'classifier':
        scoring = ['accuracy', 'precision', 'recall', 'f1']
    else:
        scoring = ['r2', 'neg_mean_squared_error', 'neg_mean_absolute_error', 'explained_variance']

    cv_results = cross_validate(model.pipe, X_train, y_train, scoring=scoring, cv=model.cv, return_train_score=False)

    if model.estimator_type == 'classifier':
        mean_scores = {k: cv_results[f'test_{k}'].mean() for k in scoring}
        df = pd.DataFrame({
            'class': ['overall'],
            'accuracy': [mean_scores['accuracy']],
            'precision': [mean_scores['precision']],
            'recall': [mean_scores['recall']],
            'fscore': [mean_scores['f1']]
        })
        model.score = df['accuracy'].iloc[0]
    else:
        mean_scores = {k: cv_results[f'test_{k}'].mean() for k in scoring}
        df = pd.DataFrame({
            'class': ['overall'],
            'r2': [mean_scores['r2']],
            'neg_mean_squared_error': [mean_scores['neg_mean_squared_error']],
            'neg_mean_absolute_error': [mean_scores['neg_mean_absolute_error']],
            'explained_variance': [mean_scores['explained_variance']]
        })
        model.score = df['r2'].iloc[0]

    model.metrics_df = df
    return df
