import numpy as np
from sklearn.decomposition import TruncatedSVD, PCA, SparsePCA

def _explainedvar(X, method, n_components, onehot, random_state, n_jobs, percentExplVar):
    if method == 'trunc_svd':
        if n_components is None:
            n_components = X.shape[1] - 1
        model = TruncatedSVD(n_components=n_components, random_state=random_state)
    elif method == 'sparse_pca':
        onehot = True
        model = SparsePCA(n_components=n_components, random_state=random_state, n_jobs=n_jobs)
    else:
        if n_components is None:
            n_components = min(X.shape)
        model = PCA(n_components=n_components, random_state=random_state)

    model.fit(X)
    loadings = model.components_
    PC = model.transform(X)

    if not onehot and percentExplVar is None:
        percentExplVar = np.cumsum(model.explained_variance_ratio_)

    return model, PC, loadings, percentExplVar
