def _cosine_similarity_from_indices(vectors: tf.Tensor, indices: tf.Tensor) -> tf.Tensor:
    gathered = tf.gather_nd(vectors, indices)
    normalized = tf.math.l2_normalize(gathered, axis=-1)
    return tf.reduce_sum(tf.reduce_prod(normalized, axis=1), axis=-1)
