import tensorflow as tf

def tf_regularization_loss(bias, l2_regularization, filters, nonlinearity, l1_regularization, Conv1d):
    losses = []

    # Base Loss Calculation
    base_loss = Conv1d.tf_regularization_loss()
    if base_loss is not None:
        losses.append(base_loss)

    # L2 Regularization
    if l2_regularization > 0.0:
        losses.append(l2_regularization * tf.nn.l2_loss(filters))
        if bias is not None:
            losses.append(l2_regularization * tf.nn.l2_loss(bias))

    # L1 Regularization
    if l1_regularization > 0.0:
        losses.append(l1_regularization * tf.reduce_sum(tf.abs(filters)))
        if bias is not None:
            losses.append(l1_regularization * tf.reduce_sum(tf.abs(bias)))

    # Nonlinearity Loss
    nonlinearity_loss = nonlinearity.regularization_loss()
    if nonlinearity_loss is not None:
        losses.append(nonlinearity_loss)

    # Final Loss Calculation
    if losses:
        return tf.add_n(losses)
    return tf.constant(0.0)
