import tensorflow as tf

def h2(u, x, dimension):
    with tf.GradientTape(persistent=True) as tape:
        tape.watch(x)
        grad = tape.gradient(u, x)
        if grad is not None:
            ans = tf.reduce_mean(u**2 + tf.reduce_sum(grad**2, axis=-1))
        else:
            ans = tf.reduce_mean(u**2)

        if grad is not None:
            for i in range(dimension):
                g = tape.gradient(grad[:, i], x)
                if g is not None:
                    ans += tf.reduce_mean(g**2)

    if ans is not None:
        return tf.sqrt(ans)
    return tf.constant(0.0, dtype=u.dtype)
```

