import tensorflow as tf

def single_strided_slice(x, axis, begin, end, step):
    # Adjust axis if it's a negative integer
    if isinstance(axis, int):
        if axis < 0:
            axis = axis % x.shape.rank
    else:
        # Adjust axis if it's a tensor/list
        axis = tf.convert_to_tensor(axis)
        if tf.rank(axis) == 0:
            axis = axis % tf.cast(tf.rank(x), axis.dtype)
        else:
            axis = tf.reshape(axis, []) % tf.cast(tf.rank(x), axis.dtype)

    # Convert to int for shape construction (works in eager/graph modes for static rank)
    axis = int(axis) if hasattr(axis, 'numpy') else axis

    shape_x = tf.shape(x)
    rank = tf.rank(x)

    # Handle None values for begin, end, step
    if begin is None:
        begin = 0
    if end is None:
        end = shape_x[axis]
    if step is None:
        step = 1

    # Construct begins, ends, and strides tensors
    begins = tf.concat([tf.zeros([axis], dtype=tf.int32), [begin], tf.zeros([rank - axis - 1], dtype=tf.int32)], axis=0)
    ends = tf.concat([shape_x[:axis], [end], shape_x[axis+1:]], axis=0)
    strides = tf.concat([tf.ones([axis], dtype=tf.int32), [step], tf.ones([rank - axis - 1], dtype=tf.int32)], axis=0)

    return tf.strided_slice(x, begins, ends, strides)
```

```python
import tensorflow as tf

def euclidean_squared(A, B):
    if A is None or B is None:
        return tf.constant([])

    sub_factor = -2 * tf.matmul(A, tf.transpose(B, perm=[0, 2, 1]))
    dotA = tf.reduce_sum(A * A, axis=2, keepdims=True)
    dotB = tf.reduce_sum(B * B, axis=2, keepdims=True)

    dist = sub_factor + dotA + dotB
    return tf.abs(dist)
```

