def tf_regularization_loss(bias, l2_regularization, filters, nonlinearity, l1_regularization):
    losses = []

    if l2_regularization > 0.0:
        losses.append(tf.nn.l2_loss(filters) * l2_regularization)
        if bias is not None:
            losses.append(tf.nn.l2_loss(bias) * l2_regularization)

    if l1_regularization > 0.0:
        losses.append(tf.reduce_sum(tf.abs(filters)) * l1_regularization)
        if bias is not None:
            losses.append(tf.reduce_sum(tf.abs(bias)) * l1_regularization)

    nonlinearity_loss = nonlinearity.regularization_loss()
    if nonlinearity_loss is not None:
        losses.append(nonlinearity_loss)

    if losses:
        return tf.add_n(losses)
    else:
        return 0
