import tensorflow as tf

def nd_indices(indices: tf.Tensor, batch_axis: int, indices_batch_major: bool) -> tf.Tensor:
    batch_size = tf.shape(indices)[batch_axis]
    batches_idxs = tf.range(batch_size)
    batches_idxs = tf.cast(batches_idxs, indices.dtype)

    for i in range(indices.shape.rank):
        if i == batch_axis:
            continue
        batches_idxs = tf.expand_dims(batches_idxs, axis=i)

    batches_idxs = tf.tile(batches_idxs, tf.shape(indices))

    if indices_batch_major:
        return tf.stack([batches_idxs, indices], axis=-1)
    else:
        return tf.stack([indices, batches_idxs], axis=-1)
