import tensorflow as tf

def forward(x, _rnn_cell, _dropout_keep_prob, _hidden_units, _use_attention, _use_dynamic, _num_layers):
    if not _use_dynamic:
        x = tf.transpose(x, [1, 0, 2])

    cell_map = {'lstm': tf.keras.layers.LSTM, 'gru': tf.keras.layers.GRU, 'rnn': tf.keras.layers.SimpleRNN}
    cell_cls = cell_map.get(_rnn_cell, tf.keras.layers.SimpleRNN)
    brnn = tf.keras.layers.Bidirectional(cell_cls(_hidden_units, return_state=True))
    _, states = brnn(x)

    if _rnn_cell == 'lstm':
        forward_state = states[0]
        backward_state = states[2]
    else:
        forward_state = states[0]
        backward_state = states[1]

    return tf.concat([forward_state, backward_state], axis=-1)
