```python
import tensorflow as tf

def pad_zeros_in_axis(x, pad_left, pad_right, axis):
    if pad_left == 0 and pad_right == 0:
        return x
    padding = [[0, 0] for _ in range(x.shape.rank)]
    padding[axis] = [pad_left, pad_right]
    return tf.pad(x, padding, mode='CONSTANT', constant_values=0)

def single_strided_slice(x, begin, end, axis):
    begin_list = [0] * x.shape.rank
    size_list = [s for s in x.shape]
    begin_list[axis] = begin
    size_list[axis] = end - begin
    return tf.slice(x, begin_list, size_list)

def slice_pad_zeros(x, begin, end, axis):
    min_frame = min(begin, end)
    left_rem = -min_frame

    if left_rem > 0:
        x = pad_zeros_in_axis(x, left_rem, 0, axis)
        begin += left_rem
        end += left_rem

    max_frame = max(begin, end)
    axis_size = x.shape[axis]
    right_rem = max_frame - axis_size

    if right_rem > 0:
        x = pad_zeros_in_axis(x, 0, right_rem, axis)

    return single_strided_slice(x, begin, end, axis)
```

```python
import tensorflow as tf

def unbroadcast_to_common_shape(value, common_shape, ignore_axes=(), allow_only_noop=False):
    if isinstance(value, tf.Tensor):
        pass
    else:
        if (isinstance(value, (int, float)) or (hasattr(value, 'ndim') and value.ndim == 0)) and len(common_shape) == 0:
            return value
        value = tf.convert_to_tensor(value)

    shape = value.shape
    ndim = shape.ndims
    if ndim is None:
        ndim = len(common_shape)

    if ndim == 0:
        for _ in range(len(common_shape)):
            value = tf.expand_dims(value, axis=0)
        shape = value.shape
        ndim = len(common_shape)

    val_shape = list(shape)
    if len(val_shape) < len(common_shape):
        val_shape = [1] * (len(common_shape) - len(val_shape)) + val_shape

    tile_multiples = []
    for v_dim, c_dim in zip(val_shape, common_shape):
        if v_dim == 1:
            tile_multiples.append(c_dim)
        else:
            tile_multiples.append(1)

    for axis in ignore_axes:
        if axis < 0:
            axis += len(tile_multiples)
        tile_multiples[axis] = 1

    if all(m == 1 for m in tile_multiples):
        return value

    if not allow_only_noop:
        value = tf.tile(value, tile_multiples)

    return value
```

```python
import numpy as np

def sigmoid(x):
    return 1.0 / (1.0 + np.exp(-x))

def parallel_sample(inpt, n_step_MC, p_0, p_1, n_chains, save_evolution, 
                    hidden_biases, visible_biases, weights, _v_dim):
    # Input handling
    if inpt is None or (hasattr(inpt, '__len__') and len(inpt) == 0):
        inpt = np.random.choice([0, 1], size=(n_chains, _v_dim), p=[p_0, p_1])
        initial_inpt = inpt.copy()
    else:
        inpt = np.asarray(inpt)
        if inpt.ndim != 2:
            inpt = inpt.reshape(n_chains, _v_dim)
        initial_inpt = inpt.copy()

    # Evolution storage
    if save_evolution:
        evolution = np.zeros((n_step_MC + 1, n_chains, _v_dim))
        evolution[0] = initial_inpt

    # Hidden layer sampling
    p_h = sigmoid(inpt @ weights.T + hidden_biases)
    h = np.random.binomial(1, p_h)

    # Monte Carlo loop
    for i in range(n_step_MC):
        p_v = sigmoid(h @ weights.T + visible_biases)
        inpt = np.random.binomial(1, p_v)
        p_h = sigmoid(inpt @ weights + hidden_biases)
        h = np.random.binomial(1, p_h)

        if save_evolution:
            evolution[i+1] = inpt

    if save_evolution:
        return inpt, p_v, initial_inpt, evolution
    else:
        return inpt, p_v, initial_inpt
```

