import torch

def likelihood_loss(y: torch.Tensor, n: torch.Tensor, p: torch.Tensor, y_mask: torch.Tensor) -> torch.Tensor:
    nll = torch.lgamma(n) + torch.lgamma(y + 1) - torch.lgamma(n + y) - n * torch.log(p) - y * torch.log(1 - p)
    if y_mask is not None:
        nll = nll * y_mask
    return nll.sum()
```

```python
def forward(x: torch.Tensor, p: float, training: bool) -> torch.Tensor:
    if not training:
        return x

    mask = torch.rand_like(x) > (1 - p)
    offsets = torch.randint(0, x.numel(), x.shape) * mask
    indices = torch.arange(x.numel())
    new_indices = (indices + offsets.flatten()) % x.numel()

    return x.flatten()[new_indices].reshape(x.shape)
