import numpy as np

def get_embedding(sample, word_embeddings, word_embeddings_size, max_len):
    aspect_word_embeddings = []
    num_positions = word_embeddings_size[1]
    for s in sample:
        word_indices = s['word_indices']
        sample_embeddings = []
        for k in range(num_positions):
            indices = word_indices.get(k, [])
            valid_indices = [idx for idx in indices if idx < max_len and idx in word_embeddings]

            if valid_indices:
                avg_emb = np.mean([word_embeddings[idx] for idx in valid_indices], axis=0)
            else:
                closest_idx = min(word_embeddings.keys(), key=lambda x: abs(x - k))
                avg_emb = word_embeddings[closest_idx]
            sample_embeddings.append(avg_emb)
        aspect_word_embeddings.append(np.array(sample_embeddings))
    return np.array(aspect_word_embeddings)
