```python
import torch

def compute_l2_distortion(pi, gamma, dx, dy):
    dist_xx = torch.sum(pi * dx**2)
    dist_yy = torch.sum(gamma * dy**2)
    dist_xy = torch.sum(pi * dx * dy)
    return dist_xx + dist_yy - 2 * dist_xy

def compute_quad_kl_divergence(pi, gamma, ref):
    return torch.sum(pi * torch.log(pi / (ref + 1e-10)))

def compute_ugw_cost(pi, gamma, a, dx, b, dy, eps, rho, rho2):
    cost = compute_l2_distortion(pi, gamma, dx, dy)
    ref = a[:, None] * b[None, :]
    cost += eps * compute_quad_kl_divergence(pi, gamma, ref)

    if rho < float('inf'):
        cost += rho * torch.sum(pi.sum(dim=1) * torch.log(pi.sum(dim=1) / (a + 1e-10)))
    if rho2 < float('inf'):
        cost += rho2 * torch.sum(gamma.sum(dim=0) * torch.log(gamma.sum(dim=0) / (b + 1e-10)))

    return cost
```

```python
import torch

TH = 0.3

def compute_loss_weight(target_actions, loss_weight_max, loss_weight_min, loss_weight_type, out_final):
    abs_actions = torch.abs(target_actions)

    if loss_weight_type == 'max':
        scale = 0.5 * (loss_weight_max - loss_weight_min)
        weight = scale * (abs_actions[:, :, 0] + abs_actions[:, :, 1]) + loss_weight_min
    elif loss_weight_type == 'med':
        abs_steering = 1.0 - torch.abs(0.5 - abs_actions[:, :, 0])
        abs_throttle = abs_actions[:, :, 1] * 2
        weight = (abs_steering + abs_throttle) / 2.0
    elif loss_weight_type == 'throttle':
        weight = abs_actions[:, :, 1] * (loss_weight_max - loss_weight_min)
    elif loss_weight_type == 'nonlinear':
        mask = abs_actions > TH
        weight = torch.where(mask, loss_weight_max, loss_weight_min).mean(dim=-1)
    elif loss_weight_type == 'steer':
        weight = torch.ones_like(abs_actions)
        weight[:, :, 1] = 0.0
    else:
        raise ValueError(f"Unknown loss_weight_type: {loss_weight_type}")

    if loss_weight_type != 'steer':
        weight = weight.unsqueeze(-1).expand(-1, -1, out_final)

    return weight
```

