```python
import torch

def forward(x: torch.Tensor, y: torch.Tensor, weight: torch.Tensor, reduction: str, eps: float) -> torch.Tensor:
    diff = x - y
    element_loss = torch.sqrt(diff ** 2 + eps)

    if reduction == 'sum':
        if weight is None:
            loss = torch.sum(element_loss) / x.shape[0]
        else:
            loss = torch.sum(weight.unsqueeze(-1) * element_loss) / x.shape[0]
    elif reduction == 'mean':
        if weight is None:
            loss = torch.mean(element_loss)
        else:
            loss = torch.sum(weight.unsqueeze(-1) * element_loss) / torch.sum(weight)

    return loss
```

```python
import torch.nn as nn

def create_net(n_inputs: int, n_outputs: int, n_layers: int, n_units: int, nonlinear: callable) -> nn.Sequential:
    if n_layers == 0:
        return nn.Linear(n_inputs, n_outputs)

    layers = [nn.Linear(n_inputs, n_units)]
    for _ in range(n_layers - 1):
        layers.append(nonlinear())
        layers.append(nn.Linear(n_units, n_units))
    layers.append(nonlinear())
    layers.append(nn.Linear(n_units, n_outputs))

    return nn.Sequential(*layers)
