import torch

def log_standard_categorical(p: torch.Tensor, reduction: str = 'mean') -> torch.Tensor:
    prior = torch.softmax(torch.ones_like(p), dim=1)
    prior.requires_grad = False
    loss = -torch.sum(p * torch.log(prior + 1e-08), dim=1)
    if reduction == 'mean':
        return loss.mean()
    elif reduction == 'sum':
        return loss.sum()
