import torch
import torch.nn.functional as F
import math

def batched_grid_apply(img, grid, batch_size=32):
    n_patches = grid.size(0)

    if n_patches > batch_size:
        n_batches = math.ceil(n_patches / batch_size)
        out = torch.empty(n_patches, img.size(1), grid.size(1), grid.size(2), dtype=img.dtype, device=img.device)

        for batch_idx in range(n_batches):
            st = batch_idx * batch_size
            end = min(st + batch_size, n_patches)

            if st >= end:
                continue

            grid_batch = grid[st:end]

            if img.size(0) != n_patches:
                img_expanded = img.expand(n_patches, -1, -1, -1).contiguous()
            else:
                img_expanded = img

            sampled = F.grid_sample(img_expanded, grid_batch, mode='bilinear', padding_mode='zeros', align_corners=False)
            out[st:end] = sampled

        return out
    else:
        if img.size(0) != n_patches:
            img_expanded = img.expand(n_patches, -1, -1, -1).contiguous()
        else:
            img_expanded = img

        return F.grid_sample(img_expanded, grid, mode='bilinear', padding_mode='zeros', align_corners=False)
