import tensorflow as tf
from tensorflow.keras import backend as K

def precision(y_true, y_pred):
    tp = tf.reduce_sum(tf.clip_by_value(y_true * y_pred, 0, 1))
    predicted_positives = tf.reduce_sum(tf.clip_by_value(y_pred, 0, 1))
    return tp / (predicted_positives + K.epsilon())

def recall(y_true, y_pred):
    tp = tf.reduce_sum(tf.clip_by_value(y_true * y_pred, 0, 1))
    possible_positives = tf.reduce_sum(tf.clip_by_value(y_true, 0, 1))
    return tp / (possible_positives + K.epsilon())

def f1(y_true, y_pred):
    prec = precision(y_true, y_pred)
    rec = recall(y_true, y_pred)
    return 2 * (prec * rec) / (prec + rec + K.epsilon())
```

