import tensorflow.keras.backend as K

def call(x, use_gated, w, U, V):
    ori_x = x
    if V is not None:
        x = K.tanh(K.dot(x, V))
    else:
        if w.shape[0] == x.shape[1]:
            x = K.dot(x, w)

    if use_gated and U is not None:
        gate_x = K.sigmoid(K.dot(ori_x, U))
        ac_x = x * gate_x
    else:
        ac_x = x

    soft_x = K.dot(ac_x, w)
    return K.transpose(K.softmax(K.transpose(soft_x)))
```

