import tensorflow as tf
from tensorflow.keras import backend as K

def weighted_bce_loss(y_true, y_pred, weight):
    bce = K.binary_crossentropy(y_true, y_pred)
    return K.mean(weight * bce)

def dice_loss(y_true, y_pred, smooth=1.0):
    y_true_f = K.flatten(y_true)
    y_pred_f = K.flatten(y_pred)
    intersection = K.sum(y_true_f * y_pred_f)
    return 1.0 - (2.0 * intersection + smooth) / (K.sum(y_true_f) + K.sum(y_pred_f) + smooth)

def weighted_bce_dice_loss(y_true, y_pred, pool_size=(50, 50), weight_factor=5.0):
    y_true = K.cast(y_true, 'float32')
    y_pred = K.cast(y_pred, 'float32')

    averaged_mask = K.pool2d(y_true, pool_size, strides=(1, 1), padding='same')

    weight = weight_factor * K.exp(-weight_factor * K.abs(averaged_mask - 0.5))
    weight = weight * K.sum(K.ones_like(weight)) / K.sum(weight)

    return weighted_bce_loss(y_true, y_pred, weight) + dice_loss(y_true, y_pred)
```

