```python
import tensorflow as tf

def call(inputs, data_format, bias1, bias2, kernel2, kernel1, use_bias):
    if data_format == 'channels_first':
        axes = (2, 3)
    else:
        axes = (1, 2)

    ex = tf.reduce_mean(inputs, axis=axes)

    ex = tf.matmul(ex, kernel1)
    if use_bias:
        ex = ex + bias1

    ex = tf.nn.relu(ex)

    ex = tf.matmul(ex, kernel2)
    if use_bias:
        ex = ex + bias2

    ex = tf.nn.sigmoid(ex)

    if data_format == 'channels_first':
        ex = tf.expand_dims(tf.expand_dims(ex, -1), -1)
    else:
        ex = tf.expand_dims(tf.expand_dims(ex, 0), 0)

    return inputs * ex
```

