from keras.preprocessing.sequence import pad_sequences
import numpy as np

def prepare_input(input_data, left_max_len, asp_max_len, max_len, config, right_max_len):
    padding = 'post'
    model_name = config.model_name
    is_aspect_term = getattr(config, 'is_aspect_term', False)
    input_pad = None

    if model_name == 'td_lstm':
        input_pad = [
            pad_sequences(input_data[0], maxlen=left_max_len, padding=padding),
            pad_sequences(input_data[1], maxlen=right_max_len, padding=padding)
        ]
    elif model_name == 'tc_lstm':
        input_pad = [
            pad_sequences(input_data[0], maxlen=left_max_len, padding=padding),
            pad_sequences(input_data[1], maxlen=right_max_len, padding=padding),
            np.array(input_data[2])
        ]
    elif model_name in ['at_lstm', 'ae_lstm', 'atae_lstm']:
        if is_aspect_term:
            input_pad = [
                pad_sequences(input_data[0], maxlen=max_len, padding=padding),
                pad_sequences(input_data[1], maxlen=asp_max_len, padding=padding)
            ]
        else:
            input_pad = [pad_sequences(input_data[0], maxlen=max_len, padding=padding)]
    elif model_name == 'ian':
        input_pad = [
            pad_sequences(input_data[0], maxlen=max_len, padding=padding),
            pad_sequences(input_data[1], maxlen=asp_max_len, padding=padding)
        ]
    elif model_name == 'cabasc':
        input_pad = [
            pad_sequences(input_data[0], maxlen=max_len, padding=padding),
            pad_sequences(input_data[1], maxlen=left_max_len, padding=padding),
            pad_sequences(input_data[2], maxlen=right_max_len, padding=padding),
            pad_sequences(input_data[3], maxlen=asp_max_len, padding=padding),
            np.array(input_data[4])
        ]
    else:
        return []

    return input_pad
