```python
def softmax(x, axis=1):
    x = K.constant(x)
    ndim = K.ndim(x)
    if ndim == 2:
        return K.softmax(x)
    elif ndim > 2:
        e = K.exp(x - K.max(x, axis=axis, keepdims=True))
        sum_e = K.sum(e, axis=axis, keepdims=True)
        return e / sum_e
    else:
        return K.constant([])
```

